"""
mkt-original | 1 Kings 1-2
Run: python3 scripts/zc-original-1kings-1-2.py

Ch 1: Royal succession — Solomon's accession; Adonijah's failed coup; anointing at Gihon
Ch 2: David's death charge to Solomon; political consolidation; Abiathar, Joab, Shimei

Key terms:
- miṯnasĕʾ (ch1v5): Hitpael of nāśāʾ, "exalted himself" — the Absalom pattern
- qereṇ haššemen (ch1v39): "horn of oil" from the tent — Mosaic anointing material
- dam māḥămâ bĕšālôm (ch2v5): "blood of war in peace" — Joab's crime defined
- lĕmallēʾ ʾeṯ-dĕḇar YHWH (ch2v27): fulfillment formula applied to Eli's house prophecy
"""

import json
import pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}


def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')


def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html


KINGS1_ORIGINAL_CH1_2 = {
    "1": {
        "1": "<p><strong>wĕhamelek Dāwîḏ zāqēn bā bayāmîm wĕlō yiḥam lô</strong>: 'And king David was old, advanced in days, and he could not get warm.' Two phrases mark the narrative's opening: <em>zāqēn bā bayāmîm</em> (old, come in days) — the standard biblical idiom for advanced age (Gen 18:11: Abraham and Sarah; Gen 24:1: Abraham alone; Josh 13:1; 23:1-2: Joshua) — and the verb <em>yiḥam</em> (Qal imperfect of <em>ḥmm</em>, to be warm), here negated: the king can no longer maintain body heat. This is the standard biblical onset-of-death marker; its significance is immediately political: a king who cannot maintain physical warmth cannot exercise executive authority.</p>",
        "2": "<p><strong>naʿărâ ḇĕṯûlâ</strong>: 'a young woman, a virgin.' The two terms are distinct: <em>naʿărâ</em> describes a young woman of marriageable age (the same word used of Rebekah in Gen 24 and Ruth gleaning in Ruth 2); <em>ḇĕṯûlâ</em> (H1330) specifies virginal status. The proposal is therapeutic — ANE medicine recognized the warming effect of body heat proximity for the elderly — not sexual. Verse 4 makes explicit that David 'did not know her' (<em>wĕhammelek lō yĕḏāʿāh</em>), a formulaic Hebrew idiom for no sexual intercourse (Gen 4:1: Adam 'knew' Eve; 1 Sam 1:19). The proposal comes from David's servants (<em>ʿăḇāḏāyw</em>), not from David himself.</p>",
        "3": "<p><strong>wayĕḇaqqĕšû naʿărâ yāp̄â bĕḵōl gĕḇûl yiśrāʾēl</strong>: 'They searched for a beautiful young woman throughout all the territory of Israel.' The search is a national operation — <em>kol gĕḇûl yiśrāʾēl</em> (the whole border/territory of Israel) is a comprehensive formula for the entire kingdom. <strong>Šûnēm</strong> (Shunem) is in the tribal territory of Issachar, in the Valley of Jezreel — the same village where the Shunammite woman will live in 2 Kings 4 (Elisha raises her son). The geographic precision is characteristic of the court archive sources underlying 1-2 Kings.</p>",
        "4": "<p><strong>wattihî lammmelek mĕšāreṯeṯ</strong>: 'she became his attendant/servant.' The verb <em>šārat</em> (Piel, to serve/minister) is used for the service of Levites in the sanctuary (Num 1:50) and for personal household service; it denotes a close attendant relationship, not a wife or concubine. The emphatic statement <em>wĕhammelek lō yĕḏāʿāh</em> legally and morally clarifies her status: Abishag is never David's wife or concubine. This distinction will have political consequences in ch 2, when Adonijah's request for Abishag is interpreted as a claim on the throne.</p>",
        "5": "<p><strong>wayyiṯnasĕʾ ʾăḏōniyyāhû</strong>: 'Adonijah exalted himself.' The verb is Hitpael of <em>nāśāʾ</em> (H5375) — reflexive/intensive, 'he lifted himself up.' The same pattern is used for Absalom (2 Sam 15:1: <em>wayyaʿaś lô ʾAḇšālôm reḵeḇ ûp̄ārāšîm</em>, chariot and horsemen). The Absalom-Adonijah parallel is structural: the third and fourth sons both attempt to seize the throne through public display and faction-building while the father lives. <strong>ʾĂnî ʾemlōk</strong>: 'I will be king' — the declarative self-assertion before any divine or royal authorization, which is the narrative's definition of the illegitimate seizure.</p>",
        "6": "<p><strong>wĕlō-ʿăṣāḇô ʾāḇîw miyyāmāyw lēʾmōr maddûaʿ kāḵâ ʿāśîṯā</strong>: 'And his father had not disciplined him at any time by saying, Why have you done this?' The verb <em>ʿāṣaḇ</em> (H6087) means to distress, grieve, or restrain — here it describes parental correction. The same parental failure appears in Eli (1 Sam 3:13: his sons did evil and he did not restrain them) and David himself with Amnon (2 Sam 13:21: David was angry but did not discipline him). The note that Adonijah was 'also very handsome in appearance' (<em>gam-hûʾ ṭôḇ tōʾar mĕʾōḏ</em>) echoes Absalom (2 Sam 14:25); external beauty without inner character creates the same trajectory.</p>",
        "7": "<p><strong>wayyihyû dĕḇārāyw ʿim Yôʾāḇ ben-Ṣĕrûyâ wĕʿim ʾAḇyāṯār hakkōhēn</strong>: 'His agreements/words were with Joab son of Zeruiah and with Abiathar the priest.' <em>Dĕḇārāyw</em> (his words/matters) here means his political negotiations or compact — an agreement to support his claim. Both Joab and Abiathar are key figures: Joab has been David's military commander throughout the Samuel narrative but has resisted David's authority repeatedly (killing Abner, Amasa, Absalom against David's explicit wishes); Abiathar is the priest from Eli's line (1 Sam 22:20) who has served David since Nob. Their alignment with Adonijah represents the older guard's faction.</p>",
        "8": "<p><strong>wĕṢāḏôq hakkōhēn ûḇĕnāyāhû ben-Yĕhôyāḏāʿ wĕNāṯān hannaḇîʾ wĕŠimʿî wĕRēʿî wĕhaggibōrîm ʾăšer lĕḏāwîḏ</strong>: Those NOT with Adonijah. The counter-faction is significant: Zadok (priest from the Eleazar line, not Eli's Abiathar line), Benaiah (commander of the elite corps), Nathan the prophet (David's court prophet since 2 Sam 7), and the <em>gibbōrîm</em> (David's professional warriors). The Zadok-Abiathar division prefigures the resolution of 2:26-27: when Abiathar is expelled, Zadok alone remains, establishing the Zadokite priestly line that will serve the Jerusalem temple through the monarchy.</p>",
        "9": "<p><strong>wayyzaḇaḥ ʾAḏōniyyāhû ṣōʾn ûḇāqār ûmĕrîʾ ʿim ʾeḇen hazzōḥeleṯ</strong>: 'Adonijah sacrificed sheep, oxen, and fattened cattle at the stone of Zoheleth.' The sacrificial feast (<em>zāḇaḥ</em>) near <strong>En-rogel</strong> (the spring at the junction of the Kidron and Hinnom valleys, southeast of Jerusalem, outside the city) is a political maneuver: the sacrificial feast would be interpreted as a covenant meal ratifying Adonijah's kingship among his supporters. The invited list is explicitly political: 'all the king's sons and all the men of Judah, the king's servants.'</p>",
        "10": "<p><strong>wĕʾeṯ-Nāṯān hannaḇîʾ wĕʾeṯ-Bĕnāyāhû wĕʾeṯ-haggibbōrîm wĕʾeṯ-šĕlōmōh ʾāḥîw lōʾ qārāʾ</strong>: 'But Nathan the prophet, Benaiah, the mighty men, and Solomon his brother he did not invite.' The deliberate exclusion of these figures from the covenant meal is the political signal: Adonijah is constituting his faction and excluding the rival faction. The exclusion of Solomon specifically marks this as a succession move. The narrator names them here to highlight the symmetry: those excluded by Adonijah are exactly those who will execute Solomon's succession.</p>",
        "11": "<p><strong>wayĕdabbēr Nāṯān ʾel-Baṯ-šeḇaʿ ʾem šĕlōmōh</strong>: Nathan goes first to Bathsheba. Nathan's stratagem (vv11-14) is political wisdom: approach the king through Bathsheba rather than directly, creating a personal and maternal stake. The phrase <em>hălōʾ šāmaʿt</em> ('have you not heard?') opens with the rhetorical question of urgent news. Nathan's characterization of Adonijah's rule as threatening to both Bathsheba and Solomon — 'that both you and Solomon will be counted as criminals (<em>ḥaṭṭāʾîm</em>)' — is the political leverage: she has a survival reason to act, not merely a promise to invoke.</p>",
        "12": "<p><strong>wĕʿattâ lĕkî ʾîṣĕʿēḵ nā ʿēṣâ</strong>: 'Now let me give you counsel.' <em>ʿĒṣâ</em> (H6098, counsel, advice) is the key political wisdom term throughout Samuel-Kings (Ahithophel's <em>ʿēṣâ</em> in 2 Sam 16-17 was 'like the word of God'). Nathan's counsel is tactically sound: have Bathsheba make the appeal on personal grounds (the king's oath) and Nathan will follow to confirm. The two-witness structure (Deut 19:15: a matter must be established by two or three witnesses) gives the appeal maximum legal weight.</p>",
        "13": "<p><strong>hălōʾ ʾattâ ʾăḏōnî-hammelek nišbaʿtā lăʾămaṯĕkā lēʾmōr kî šĕlōmōh binkā yimlōk ʾaḥărāy</strong>: 'Did you not, my lord the king, swear to your handmaid saying, Your son Solomon shall reign after me?' The oath invoked here has no prior narrative documentation in 2 Samuel — it is presupposed as historical fact. The formula <em>nišbaʿtā</em> (Niphal perfect of <em>šāḇaʿ</em>, to swear) is the standard covenant-oath verb. Bathsheba's self-designation as <em>ʾămaṯĕkā</em> (your female slave/handmaid) is the formal court address of petition — it invokes covenant obligation, not merely personal relationship.</p>",
        "14": "<p><strong>hinnēh ʿôḏēḵ mĕḏabbereṯ šām ʿim-hammelek wĕʾanî ʾāḇôʾ ʾaḥărāyiḵ</strong>: 'Behold, while you are still speaking there with the king, I will come in after you.' Nathan's timing is precise — Bathsheba makes the initial petition, creating the emotional and legal grounds, and Nathan follows to confirm. The sequential structure (woman first, prophet second) maximizes the impact: a mother's personal stake, then prophetic confirmation. This is political strategy by those who believe they are acting in accordance with God's choice.</p>",
        "15": "<p><strong>waṯābōʾ Baṯ-šeḇaʿ ʾel-hammelek haḥăḏrâ</strong>: 'Bathsheba came to the king in the inner chamber.' The <em>ḥeḏer</em> (inner chamber) is the most private room — David is being tended by Abishag. The scene underscores David's physical diminishment: the king who was once the most dynamic military and political figure in Israel now lies in the inner chamber unable to keep warm. Bathsheba enters, prostrates herself (<em>waṯiqqōḏ waṯišṯaḥû lammmelek</em>), and waits for him to ask her purpose.</p>",
        "16": "<p><strong>waṯiqqōḏ Baṯ-šeḇaʿ waṯišṯaḥû lammmelek</strong>: 'Bathsheba bowed and prostrated herself to the king.' The verb pair <em>qāḏad</em> (to bow the head) + <em>šāḥâ</em> (to prostrate oneself) is the royal obeisance formula — used of subjects before kings and of worshipers before YHWH. By contrast, when Bathsheba later comes before Solomon in v16 (ch 2:19), <em>he</em> rises and bows to <em>her</em> — a reversal that demonstrates Solomon's honor to his mother and the changed political reality.</p>",
        "17": "<p><strong>wayĕdabbēr ʾaḏōnî ʾeloyhēkā YHWH ʾel-ʾămaṯĕkā lēʾmōr</strong>: The invocation of 'YHWH your God' (using the third person to refer to the Lord) in Bathsheba's petition elevates the claim from personal request to covenantal obligation. David's oath was sworn by YHWH (<em>ḥay YHWH</em>, 'as YHWH lives', v29 confirms this formula) — breaking it would be not merely political failure but covenant perjury. The appeal grounds Solomon's succession in divine promise, not human political maneuvering.</p>",
        "18": "<p><strong>wĕʿattâ hinnēh ʾAḏōniyyāhû mālaḵ</strong>: 'And now, behold, Adonijah has become king.' The perfect tense <em>mālaḵ</em> — 'has become king,' presenting it as an accomplished fact rather than ongoing process — is the rhetorical framing of urgency. Bathsheba presents the succession as a fait accompli that David must reverse, not a plan he can prevent. The appeal to David's ignorance ('you did not know it') may be slightly overstated — the narrative does not say David was completely unaware of Adonijah's actions — but politically it grants David the face-saving option of acting without acknowledging that he had passively allowed the situation to develop.</p>",
        "19": "<p><strong>wayyzaḇaḥ šôr ûmĕrîʾ wĕṣōʾn lārōḇ wayyiqrāʾ lĕḵol bĕnê hammmelek</strong>: 'He sacrificed oxen and fattened cattle and sheep in abundance and invited all the king's sons.' The repetition of the feast-detail from v9 is Bathsheba's report to David — the narrative deliberately repeats the information to show what David was being told. The phrase <em>wĕlišĕlōmōh ʿaḇdĕkā lōʾ qārāʾ</em> (and Solomon your servant he did not call) is the pivot of the petition: Solomon's exclusion is the evidence that the succession is being stolen, and it personalizes the abstract political claim.</p>",
        "20": "<p><strong>wĕʾattâ ʾăḏōnî-hammelek ʿênê kol-yiśrāʾēl ʿāleykā lĕhaggîḏ lāhem mî yēšēḇ ʿal-kissēʾ ʾăḏōnî-hammelek ʾaḥărāyw</strong>: 'And now, my lord the king, the eyes of all Israel are upon you, to tell them who will sit on the throne of my lord the king after him.' The phrase <em>ʿênê kol-yiśrāʾēl ʿāleykā</em> (the eyes of all Israel are upon you) is a political and covenantal pressure statement — the king has a public obligation to declare his succession. 'Eyes upon' is a standard idiom for expectant attention requiring response. The question is not merely dynastic but concerns the stability of the covenant community.</p>",
        "21": "<p><strong>wĕhāyâ kĕšeḵeḇ ʾăḏōnî-hammelek ʿim-ʾăḇōṯāyw wĕhāyîṯî ʾanî ûḇĕnî šĕlōmōh ḥaṭṭāʾîm</strong>: 'And it will be, when my lord the king lies with his fathers, that I and my son Solomon will be regarded as criminals.' The idiom <em>šāḵaḇ ʿim ʾăḇōṯāyw</em> (to lie with one's fathers) is the standard death formula for Israelite kings throughout 1-2 Kings — it will appear dozens of times. <em>Ḥaṭṭāʾîm</em> (sinners/criminals) — those who have violated the law. Bathsheba frames the political danger in the sharpest terms: if Solomon is passed over, she and Solomon will be treated as rebels against the new king.</p>",
        "22": "<p><strong>wĕhinnēh ʿôḏennāh mĕḏabbereṯ ʿim-hammelek wĕNāṯān hannaḇîʾ bāʾ</strong>: 'And while she was still speaking with the king, Nathan the prophet came.' The narrative timing — Nathan arrives precisely while Bathsheba is speaking — is either coordinated (as Nathan told her in v14) or presented as providentially timed. The two-witness structure is completed: Bathsheba makes the petition, Nathan arrives to confirm it. The narrator uses the same phrasing as Nathan's instruction to create a ring structure confirming the plan worked exactly as devised.</p>",
        "23": "<p><strong>wayuggad lammmelek lēʾmōr hinnēh Nāṯān hannaḇîʾ</strong>: Nathan is formally announced to the king — the court announcement protocol. His entry after Bathsheba follows the sequence Nathan prescribed; his presence confirms that both advisors are aligned on the matter. The parallel announcement formulas (Bathsheba prostrating in v16, Nathan prostrating in v23 with <em>wayyišṯaḥû lammmelek ʾappāyw ʾarṣâ</em>) create a literary balance: two witnesses, two prostrations, one message.</p>",
        "24": "<p><strong>wayyōʾmer Nāṯān ʾăḏōnî hammelek ʾattâ āmartā ʾAḏōniyyāhû yimlōk ʾaḥărāy wĕhûʾ yēšēḇ ʿal-kissĕʾî</strong>: Nathan's approach is indirect — he does not say 'you promised Solomon.' Instead he asks: 'Did you say Adonijah shall reign?' This rhetorical strategy forces David to either deny or affirm, without Nathan presuming to accuse the king. The rhetorical question (<em>ʾattâ āmartā</em>) invites David to repudiate Adonijah's kingship on his own initiative rather than at Nathan's instruction.</p>",
        "25": "<p><strong>kî yāraḏ hayyôm wayyizbaḥ šôr ûmĕrîʾ wĕṣōʾn lārōḇ</strong>: 'For today he has gone down and sacrificed oxen and fattened cattle and sheep in abundance.' The third repetition of the feast-detail (vv9, 19, 25) drives the point into David's consciousness. The phrase <em>wayyōmal wayyēšt lĕp̄ānāyw wayyōmĕrû yĕḥî hammmelek ʾAḏōniyyāhû</em> (and they are eating and drinking before him and saying, Long live King Adonijah!) mimics the exact formula that will be used for Solomon (v39: <em>yĕḥî hammmelek šĕlōmōh</em>) — the same formal proclamation formula, applied to the wrong king. Nathan is dramatizing the urgency.</p>",
        "26": "<p><strong>wĕlî ʾanî-ʿaḇdĕkā wĕlĕṢāḏôq hakkōhēn ûlĕḇĕnāyāhû ben-Yĕhôyāḏāʿ ûlišĕlōmōh ʿaḇdĕkā lōʾ qārāʾ</strong>: The list of those not invited corresponds exactly to the faction listed in v8 as loyal to Solomon. Nathan articulates his own exclusion alongside Zadok, Benaiah, and Solomon — placing himself in the company of the legitimate succession supporters. The self-description as <em>ʿaḇdĕkā</em> (your servant) throughout these verses is court protocol, not merely deference; it signals loyal covenant-servant status.</p>",
        "27": "<p><strong>ʾim mēʾēṯ ʾăḏōnî-hammelek nihyâ haddāḇār hazzeh</strong>: 'Was this thing done by my lord the king?' The question is designed to force David's hand: either the succession was deliberately given to Adonijah (in which case Nathan and the others need to know) or it was not (in which case David must act). Nathan's closing <em>wĕlōʾ hôḏaʿtā ʾeṯ-ʿaḇdĕkā mî yēšēḇ ʿal-kissēʾ ʾăḏōnî-hammelek ʾaḥărāyw</em> (and you have not informed your servant who would sit on the throne) is deniably accusatory — you left us in the dark — pressing for explicit royal declaration.</p>",
        "28": "<p><strong>wayyaʿan hammmelek Dāwîḏ wayyōʾmer qirĕʾû-lî lĕḇaṯ-šeḇaʿ</strong>: 'King David answered and said, Call Bathsheba to me.' David's response is immediate — he calls Bathsheba back in (she had presumably left when Nathan arrived) and delivers his oath. The scene pivots: David moves from passivity (lying in the inner chamber unable to get warm) to decisive royal action. The oath formula he pronounces (v29-30) is the most formal possible: sworn by YHWH, invoking his own redemption from adversity.</p>",
        "29": "<p><strong>ḥay YHWH ʾăšer pāḏâ ʾeṯ-nap̄šî mikkol-ṣārâ</strong>: 'As YHWH lives, who has redeemed my soul from all adversity.' The oath formula <em>ḥay YHWH</em> (as YHWH lives) is the standard Hebrew oath-swearing formula, invoking YHWH as the living guarantor of the pledge. The relative clause — 'who has redeemed my soul from all adversity' — makes the oath deeply personal: it invokes David's entire history of divine deliverance (the theme of 2 Sam 22 = Psalm 18, where YHWH is the one who rescued David from all enemies). The verb <em>pāḏâ</em> (to redeem by paying a price, H6299) is the covenantal redemption term, distinct from <em>gāʾal</em> (kinsman-redeemer).</p>",
        "30": "<p><strong>kî kaʾăšer nišbaʿtî lāḵ bĕYHWH ʾĕlōhê yiśrāʾēl lēʾmōr kî-šĕlōmōh binkā yimlōk ʾaḥărāy</strong>: 'Just as I swore to you by YHWH the God of Israel saying, Solomon your son shall reign after me.' The oath is now confirmed — <em>nišbaʿtî</em> (I swore) + the specific content + the formula <em>kî ḵēn ʾeʿĕśeh hayyôm hazzeh</em> (so I will do this day). The immediate execution ('this day') is the characteristic urgency of royal decree in the Samuel-Kings narrative: when the king decides, action follows without delay. The three witnesses to this re-confirmation of the oath are Bathsheba, Nathan, and implicitly Abishag who is present.</p>",
        "31": "<p><strong>waṯiqqōḏ Baṯ-šeḇaʿ ʾappāyw ʾarṣâ waṯišṯaḥû lammmelek waṯōʾmer yĕḥî ʾăḏōnî hammmelek Dāwîḏ lĕʿōlām</strong>: 'Bathsheba bowed with her face to the ground and prostrated herself to the king and said, May my lord King David live forever!' The proclamation <em>yĕḥî hammmelek</em> (long live the king!) + his name + <em>lĕʿōlām</em> (forever) is the formal royal acclamation. Bathsheba's response is the formal court expression of gratitude and loyalty. The <em>lĕʿōlām</em> (forever) is formulaic courtesy, not a literal claim of immortality — similar expressions appear throughout the ancient Near East as royal acclamation formulae.</p>",
        "32": "<p><strong>wayyōʾmer hammmelek Dāwîḏ qirĕʾû-lî lĕṢāḏôq hakkōhēn ûlĕNāṯān hannaḇîʾ ûlĭḇĕnāyāhû ben-Yĕhôyāḏāʿ</strong>: David summons the three key actors for Solomon's anointing: Zadok the priest, Nathan the prophet, and Benaiah the military commander. The triad represents the three institutions of legitimate authority: priestly, prophetic, and military. This is the institutional support structure that legitimizes the succession. Notably absent: Joab (the military commander who went with Adonijah) and Abiathar (the priest who supported Adonijah). The succession is constituted by the replacement faction.</p>",
        "33": "<p><strong>wĕhirkabtem ʾeṯ-binkā šĕlōmōh ʿal-happirĕḏâ ʾăšer-lî</strong>: 'Have my son Solomon ride on my own mule.' The king's personal mule (<em>pirĕḏâ</em>) is the most important detail of the anointing procession: in the ancient Near East, riding the king's personal animal was equivalent to a public declaration of succession. David's mule is the physical symbol of royal authority being transferred. Compare Absalom's mule in 2 Sam 18:9 — Absalom was riding 'the king's mule' when he got caught in the oak tree, suggesting that claiming the royal mule was already part of the succession-claim protocol.</p>",
        "34": "<p><strong>ûmāšaḥ ʾōṯô šām Ṣāḏôq hakkōhēn wĕNāṯān hannaḇîʾ lĕmelek ʿal-yiśrāʾēl</strong>: 'And let Zadok the priest and Nathan the prophet anoint him there as king over Israel.' The double anointing — priest and prophet together — is unprecedented in the biblical narrative; David was anointed by Samuel alone (1 Sam 16:13), and Saul was anointed by Samuel alone (1 Sam 10:1). The double anointing of Solomon by both priest and prophet underscores the institutional legitimacy of his succession: priestly sanction and prophetic confirmation simultaneously. The <em>wĕqĕraʾtem qôl haššôp̄ār</em> (blow the shofar) announces the proclamation publicly.</p>",
        "35": "<p><strong>ûḇāʾtem ʾaḥărāyw wĕḇāʾ wĕyāšaḇ ʿal-kissĕʾî ûhûʾ yimlōk taḥtāy</strong>: 'Come after him, and he shall come and sit on my throne, for he shall be king in my place.' The formula <em>ûhûʾ yimlōk taḥtāy</em> (he shall reign in my place) — taḥtāy (H8478) literally 'under me' or 'in my stead' — is the formal succession declaration. David appoints Solomon in his own place while still living: a co-regency arrangement. The appointment of Solomon over both Israel and Judah (<em>lĕmelek ʿal-yiśrāʾēl wĕʿal-yĕhûḏâ</em>) — listing both — signals the pan-Israelite scope of the succession.</p>",
        "36": "<p><strong>wayyaʿan Bĕnāyāhû ben-Yĕhôyāḏāʿ ʾeṯ-hammelek wayyōʾmer ʾāmēn kēn yōʾmar YHWH</strong>: Benaiah's response — <em>ʾāmēn</em> (so be it, verily) + <em>kēn yōʾmar YHWH ʾĕlōhê ʾăḏōnî hammelek</em> (may YHWH, the God of my lord the king, say so) — is one of the earliest uses of <em>ʾāmēn</em> as a liturgical affirmation in the Hebrew Bible. The term derives from the root <em>ʾmn</em> (firmness, faithfulness, reliability) and affirms the content of what has been declared. Benaiah's response constitutes the military institution's formal assent to the succession.</p>",
        "37": "<p><strong>kaʾăšer hāyâ YHWH ʿim-ʾăḏōnî hammmelek kēn yihyeh ʿim-šĕlōmōh</strong>: 'As YHWH was with my lord the king, so may he be with Solomon.' Benaiah's blessing invokes the YHWH-with formula (<em>YHWH ʿimmaḵā</em>) — the covenant-presence language that runs through the entire Deuteronomistic History (Josh 1:5: YHWH promises to be with Joshua as with Moses; 1 Sam 18:12, 14: YHWH was with David). The explicit wish that Solomon receive the same divine presence that David had is theologically loaded — it acknowledges that David's success was due to divine accompaniment, and petitions the same for the new king. The continuation — <em>wîgaḏdēl ʾeṯ-kissĕʾô miqqissĕʾ ʾăḏōnî hammmelek Dāwîḏ</em> (and make his throne greater than the throne of my lord King David) — is the succession-blessing formula.</p>",
        "38": "<p><strong>wayyēreḏ Ṣāḏôq hakkōhēn wĕNāṯān hannaḇîʾ ûḇĕnāyāhû ben-Yĕhôyāḏāʿ wĕhakkĕrēṯî wĕhappĕlēṯî</strong>: 'So Zadok the priest and Nathan the prophet and Benaiah son of Jehoiada and the Cherethites and the Pelethites went down.' The <em>kĕrēṯî ûp̄ĕlēṯî</em> (Cherethites and Pelethites) are David's elite foreign bodyguard — mercenaries of Philistine/Aegean origin who formed the royal personal guard throughout David's reign (2 Sam 8:18; 15:18; 20:7, 23). Their presence in Solomon's anointing procession signals military continuity and the professional army's allegiance to the new king.</p>",
        "39": "<p><strong>wayyiqqaḥ Ṣāḏôq hakkōhēn ʾeṯ-qereṇ haššemen mēhāʾōhel wayyimšaḥ ʾeṯ-šĕlōmōh</strong>: 'Zadok the priest took the horn of oil from the tent and anointed Solomon.' The <em>qereṇ haššemen mēhāʾōhel</em> (horn of oil from the tent) specifies the sacred anointing oil from the tabernacle — the tent David had set up for the Ark in Jerusalem (2 Sam 6:17). The use of tabernacle oil connects Solomon's anointing to the Mosaic tradition: the same holy anointing oil (<em>šemen hamišḥâ</em>, Exod 30:23-33) used to consecrate the tabernacle and Aaron's priestly line is used to consecrate the Davidic king. The ram's horn as vessel for the anointing oil echoes Samuel's anointing of David (1 Sam 16:13 uses a <em>qāren</em> horn).</p>",
        "40": "<p><strong>wayiqqĕʿû baššôp̄ār wayyōmĕrû kol-hāʿām yĕḥî hammmelek šĕlōmōh</strong>: 'They blew the shofar and all the people said, Long live King Solomon!' The <em>šôp̄ār</em> (ram's horn trumpet) was the standard instrument for public royal proclamations, military signals, and religious assemblies. Its sounding announces the succession to the entire city and surrounding area. The tricolon <em>ʿōlîm ʾaḥārāyw kol-hāʿām mĕḥallĕlîm baḥălîlîm ûśĕmēḥîm śimḥâ gĕḏôlâ</em> (all the people came up after him playing flutes and rejoicing with great joy) is a festal joy-procession formula — the city is given over to celebration. <em>Ḥălîlîm</em> (flutes/pipes) appear in festal contexts throughout the OT.</p>",
        "41": "<p><strong>wayyišmaʿ ʾAḏōniyyāhû wĕḵol-haqqĕrûʾîm ʾăšer ʾittô wĕhēm killû leʾĕkōl</strong>: 'Adonijah and all the guests who were with him heard it, and they had just finished eating.' The dramatic irony is pointed: Adonijah's coronation feast is interrupted mid-celebration by the sound of Solomon's anointing procession. The phrase <em>wattirʿaš hāʿîr</em> (the city was in uproar) describes the overwhelming public noise of Solomon's celebration reaching Adonijah's feast at En-rogel outside the city. Joab's question — 'What is this noise of the city in uproar?' — is the moment Adonijah's faction realizes their bid has failed.</p>",
        "42": "<p><strong>ʿôḏennû mĕḏabbēr wĕhinnēh Yônāṯān ben-ʾAḇyāṯār hakkōhēn bāʾ</strong>: 'While he was still speaking, behold, Jonathan son of Abiathar the priest came.' The messenger Jonathan son of Abiathar (not Jonathan the son of Saul) is the bearer of catastrophic news for Adonijah's faction. Adonijah's greeting — <em>bōʾ kî ʾîš ḥayil ʾattâ ûṭôḇ tĕḇassēr</em> (come, for you are a valiant man and bring good news) — uses the root <em>bśr</em> (to bring news, especially good/victory news), the same root as <em>bĕśôrâ</em> and NT <em>euangelion</em> (gospel). Adonijah hopes for a good-news report; he receives the opposite.</p>",
        "43": "<p><strong>wayyaʿan Yônāṯān wayyōʾmer lĕʾAḏōniyyāhû ʾāḵēn ʾăḏōnênû hammmelek Dāwîḏ himmĕlîḵ ʾeṯ-šĕlōmōh</strong>: 'Jonathan answered Adonijah, Truly/indeed our lord King David has made Solomon king.' The adverb <em>ʾāḵēn</em> (truly, indeed, on the contrary) is a strong affirmative/adversative particle that signals the news will overturn expectations. The perfect <em>himmĕlîḵ</em> (has made king) is the accomplished fact. Jonathan's report is a detailed account of the anointing procession — emphasizing all the institutional actors (Zadok, Nathan, Benaiah, the Cherethites/Pelethites) to establish the legitimacy of what has occurred.</p>",
        "44": "<p><strong>wayišlaḥ ʾittô hammelek ʾeṯ-Ṣāḏôq hakkōhēn wĕʾeṯ-Nāṯān hannaḇîʾ ûḇĕnāyāhû ben-Yĕhôyāḏāʿ</strong>: The messenger repeats the three institutional actors in v44 — king sent with him (Solomon) Zadok, Nathan, Benaiah. The repetition of the institutional triumvirate in the messenger's report mirrors the original commission in v32-34, creating a narrative confirmation that the succession happened exactly as David commanded. The narrative structure itself validates the succession's legitimacy.</p>",
        "45": "<p><strong>wayyimšaḥû ʾōṯô Ṣāḏôq hakkōhēn wĕNāṯān hannaḇîʾ lĕmelek bĕGîḥôn</strong>: 'And Zadok the priest and Nathan the prophet have anointed him king at Gihon.' <strong>Gihon</strong> (<em>Gîḥôn</em>) is the spring on the eastern slope of the City of David, the primary water source for Jerusalem. Its selection as anointing site is significant: water-source ceremonies in the ancient Near East had sacred associations, and Gihon's prominence in Jerusalem's water system (later connected to Hezekiah's tunnel) made it a natural public gathering point. The proclamation and public celebration at Gihon allows the news to spread immediately through the city.</p>",
        "46": "<p><strong>wĕgam yāšaḇ šĕlōmōh ʿal kissēʾ hammamlāḵâ</strong>: 'And moreover Solomon sits on the royal throne.' The verb <em>yāšaḇ</em> (to sit) in the context of 'sitting on the throne' is the standard formula for enthroned royal authority — the king 'sits' as a technical expression for exercising judicial and executive power (Ps 9:4: 'you sat on the throne judging righteously'). The messenger's declaration — Solomon is already seated on the throne — is the final proof that the coup attempt has completely failed and Adonijah's faction must immediately recalibrate.</p>",
        "47": "<p><strong>wĕgam bāʾû ʿaḇdê hammelek lĕḇārēḵ ʾeṯ-ʾăḏōnênû hammmelek Dāwîḏ</strong>: 'And moreover the king's servants came to bless our lord King David.' The royal servants' blessing formula — <em>yĕhî ʾĕlōheykā ʾeṯ-šēm šĕlōmōh ṭôḇ miššĕmeḵā</em> (may your God make the name of Solomon better than your name) — is the court acclamation that the new king's name will be even greater than the old king's. The response of David — <em>wayyišṯaḥû hammmelek ʿal-hammiššāh</em> (and the king bowed himself on the bed) — is the physical act of worship: David, lying in bed, bows in gratitude to YHWH. The physical diminishment (he can only bow while lying) makes the act of thanksgiving more poignant.</p>",
        "48": "<p><strong>bārûḵ YHWH ʾĕlōhê yiśrāʾēl ʾăšer nāṯan hayyôm yōšēḇ ʿal-kissĕʾî wĕʿênay rōʾôṯ</strong>: David's blessing — 'Blessed is YHWH God of Israel who has given one to sit on my throne today while my own eyes see it.' The formula <em>bārûḵ YHWH</em> is the standard Hebrew blessing doxology — giving YHWH the credit for what has occurred. The phrase <em>wĕʿênay rōʾôṯ</em> (and my own eyes seeing it) is the personal testimony of witnessed fulfillment — David has lived to see the covenant promise fulfilled. The Davidic covenant of 2 Sam 7 promised that a son of David would succeed him on the throne; this is the beginning of that fulfillment.</p>",
        "49": "<p><strong>wayyeḥĕrĕḏû wayyāqûmû kol-haqqĕrûʾîm ʾăšer lĕʾAḏōniyyāhû wayyēlĕḵû ʾîš lĕḏarKô</strong>: 'All the guests who were with Adonijah trembled and rose and each went his own way.' The verb <em>ḥāraḏ</em> (to tremble, shudder) describes the sudden terror of Adonijah's supporters when they realize the coup has failed. The immediate dispersal — 'each went his own way' — is the dissolution of the political faction. In ANE political culture, association with a failed claimant to the throne was potentially capital; the guests' flight is self-preservation. The rapid dispersal demonstrates that Adonijah's faction had no deep commitment — it was opportunistic alignment with an apparently successful pretender, not a principled political movement.</p>",
        "50": "<p><strong>wĕʾAḏōniyyāhû yārēʾ mippĕnê šĕlōmōh wayyāqom wayyēleḵ wayyaḥăzēq bĕqarnôṯ hammizbēaḥ</strong>: 'Adonijah feared Solomon and rose and went and took hold of the horns of the altar.' The altar sanctuary was the traditional place of refuge — Exod 21:13-14 permits the accidental manslayer to flee to a 'place' (later understood as the altar), but explicitly excludes the premeditated murderer. The altar horns (<em>qarnôṯ hammizbēaḥ</em>) are the four raised corners of the altar that the priest touched with the blood of sin offerings (Lev 4:18; Exod 30:10) — grasping them was the equivalent of grabbing sanctuary. Adonijah's action is an appeal for mercy: he puts himself in the space of divine mercy.</p>",
        "51": "<p><strong>wayuggad lišĕlōmōh lēʾmōr hinnēh ʾAḏōniyyāhû yārēʾ ʾeṯ-hammmelek šĕlōmōh</strong>: 'It was told Solomon, Behold, Adonijah fears King Solomon.' The report reaching Solomon frames Adonijah's altar-clinging as fear of Solomon personally rather than appeal for divine mercy — a politically accurate reading. Adonijah sends his request through intermediaries: <em>yiššāḇaʿ-lî kayyôm hammmelek šĕlōmōh ʾim-yahărōg ʾeṯ-ʿaḇdô baḥereb</em> (let King Solomon swear to me today that he will not kill his servant with the sword). The request is for a formal oath of safety, not merely informal mercy.</p>",
        "52": "<p><strong>wayyōʾmer šĕlōmōh ʾim yihyeh lĕben-ḥayil lōʾ-yippōl misśaʿărāṯô ʾarṣâ</strong>: 'Solomon said, If he shows himself worthy (<em>ben-ḥayil</em>), not one of his hairs will fall to the earth.' <em>Ben-ḥayil</em> (son of valor/worth) is the standard term for a man of quality and loyalty. Solomon's conditional pardon is precise: ongoing loyalty will bring safety; wickedness will bring death. This is the conditional covenant formula applied to the political situation — the same structure as the conditional Davidic covenant (2:4: 'if your sons take heed to their way'). Solomon's mercy is real but not unconditional.</p>",
        "53": "<p><strong>wayyišlaḥ hammmelek šĕlōmōh wayyōrîḏûhû mēʿal hammizbēaḥ wayyāḇōʾ wayyišṯaḥû lammmelek šĕlōmōh</strong>: 'King Solomon sent and they brought him down from the altar, and he came and bowed before King Solomon.' Adonijah's prostration before Solomon — <em>wayyišṯaḥû lammmelek šĕlōmōh</em> — is the formal submission of the defeated claimant to the victorious king. Solomon's dismissal — <em>lēḵ lĕḇêṯeḵā</em> (go to your house) — is the royal command sending Adonijah under informal house arrest, a mercy compared to execution. The chapter ends with Adonijah alive because of Solomon's conditional mercy — a mercy Adonijah will subsequently abuse (ch 2:13-25).</p>"
    },
    "2": {
        "1": "<p><strong>wayyiqrĕḇû yĕmê-Dāwîḏ lāmûṯ wayyĕṣaw ʾeṯ-šĕlōmōh bĕnô</strong>: 'The days of David drew near that he should die, and he charged his son Solomon.' The phrase <em>wayyiqrĕḇû yĕmê X lāmûṯ</em> (the days of X drew near to die) is the standard deathbed narrative opening (Gen 47:29: Jacob; Deut 31:14: Moses). David's charge to Solomon is the royal testament — the dying father's final counsel to his successor, parallel in structure to Moses's farewell speeches (Deut 31-33), Jacob's deathbed blessings (Gen 49), and Joshua's farewell (Josh 23-24). The formal genre signals the ideological importance of what follows.</p>",
        "2": "<p><strong>ʾānōḵî hōlēḵ bĕḏereḵ kol-hāʾāreṣ wĕḥāzaqtā wĕhāyîṯā lĕʾîš</strong>: 'I am going the way of all the earth. Be strong and show yourself a man.' The phrase <em>ḏereḵ kol-hāʾāreṣ</em> (the way of all the earth) is a Hebrew euphemism for death — all earthly beings travel this path. The commission formula <em>ḥāzaq wihyēh lĕʾîš</em> (be strong and be a man/show yourself a man) echoes the standard commissioning language: YHWH to Joshua (Josh 1:6, 7, 9: <em>ḥāzaq weʾĕmāṣ</em>), David to Solomon in 1 Chr 28:20. The combination of physical courage with moral fidelity is the Deuteronomic ideal of kingship: external strength rooted in internal obedience.</p>",
        "3": "<p><strong>wĕšāmartā ʾeṯ-mišmereṯ YHWH ʾĕlōheykā laḥăleḵeṯ biḏrāḵāyw lišmōr ḥuqqōṯāyw miṣwōṯāyw ûmišpāṭāyw wĕʿēḏwōṯāyw</strong>: 'Keep the charge of YHWH your God, walking in his ways, keeping his statutes, commandments, ordinances, and testimonies.' The fourfold law vocabulary — <em>ḥuqqōṯ</em> (statutes, practices), <em>miṣwōṯ</em> (commandments), <em>mišpāṭîm</em> (ordinances/judgments), <em>ʿēḏwōṯ</em> (testimonies) — is the full Deuteronomic law-formula that appears in Deuteronomy 4:45; 6:1; Ps 119 (all four terms throughout the psalm). This is the fullest possible expression of Torah faithfulness, covering every category of covenant obligation. The instruction is explicitly grounded in 'what is written in the Torah of Moses.'</p>",
        "4": "<p><strong>lĕmaʿan yāqîm YHWH ʾeṯ-dĕḇārô ʾăšer dibbēr ʿālay lēʾmōr ʾim-yišmĕrû ḇāneyḵā ʾeṯ-darKām laḥăleḵeṯ lĕp̄ānay beʾĕmeṯ bĕḵol-lĕḇāḇām ûḇĕḵol-nap̄šām</strong>: 'That YHWH may establish his word that he spoke concerning me, saying, If your sons keep their way, to walk before me in truth with all their heart and with all their soul, you shall not lack a man on the throne of Israel.' The conditional clause — <em>ʾim-yišmĕrû ḇāneyḵā</em> (if your sons keep) — reveals the conditionality of the Davidic covenant that is usually overlooked. The unconditional aspect is the dynasty's existence; the conditional aspect is its specific kings' continued possession of the throne. The formula <em>bĕḵol-lĕḇāḇām ûḇĕḵol-nap̄šām</em> (with all their heart and with all their soul) is the Shema formula (Deut 6:5), making obedience to Torah the explicit condition of covenant blessing.</p>",
        "5": "<p><strong>wĕgam ʾattâ yāḏaʿtā ʾēṯ ʾăšer-ʿāśâ lî Yôʾāḇ ben-Ṣĕrûyâ ʾăšer ʿāśâ lišnê śārê ṣiḇĕʾōṯ yiśrāʾēl lĕʾAḇnēr ben-Nēr ûlĕʿAmāśāʾ ben-Yeṯer</strong>: 'You also know what Joab son of Zeruiah did to me, what he did to the two commanders of the armies of Israel, to Abner son of Ner and to Amasa son of Jether.' The key phrase is <em>wayyāśem dĕmê milḥāmâ bĕšālôm</em> (he shed blood of war in peacetime): Joab killed Abner and Amasa not in battle but during peacetime negotiations and political transitions (2 Sam 3:27; 20:10), making their deaths murders rather than legitimate warfare. <em>Dam milḥāmâ bĕšālôm</em> (blood of war in peace) is the legal definition: killing with war's violence during peace's terms = murder.</p>",
        "6": "<p><strong>wĕʿāśîṯā kĕḥokmāṯeḵā wĕlōʾ-ṯôrēd śêḇāṯô bĕšālôm šĕʾôl</strong>: 'Act according to your wisdom and do not let his gray hair go down to Sheol in peace.' <em>Ḵokmāṯeḵā</em> (your wisdom) — the appeal to wisdom rather than specific instruction anticipates the entire Solomon narrative, whose theological center is wisdom (the gift of 1 Kings 3). David trusts Solomon's judgment to find the appropriate means for bringing Joab to account. <em>Śêḇâ</em> (gray head, old age) is a metonym for the person at the end of life — 'do not let his gray hair descend peacefully to Sheol' means: he should not die in his bed of old age, unpunished for his crimes.</p>",
        "7": "<p><strong>ûlĕḇĕnê Barzillay haggĭlʿāḏî taʿăśeh ḥeseḏ wĕhāyû bĕʾōḵĕlê šulḥāneḵā</strong>: 'Deal loyally with the sons of Barzillai the Gileadite and let them be among those who eat at your table.' The instruction regarding Barzillai's sons is the positive counterpart to the negative instructions about Joab and Shimei. <em>Ḥeseḏ</em> (covenant loyalty, steadfast love) is the specific obligation: Barzillai had supported David during Absalom's rebellion (2 Sam 17:27-29; 19:31-40), and this <em>ḥeseḏ</em> creates an ongoing obligation of reciprocal loyalty. The phrase 'eat at your table' (<em>ʾāḵal bĕšulḥāneḵā</em>) is the covenant-belonging idiom — the same formula used for Mephibosheth in 2 Sam 9:7-13.</p>",
        "8": "<p><strong>wĕhinnēh ʿimmĕkā Šimʿî ben-Gērāʾ ben-hayyĕmînî miBaḥûrîm</strong>: 'Behold, with you is Shimei son of Gera the Benjaminite from Bahurim.' Shimei cursed David during Absalom's rebellion (<em>bĕyôm lĕktî maḥănāyim</em>, 2 Sam 16:5-8) — 'on the day I went to Mahanaim.' David spared him when returning victorious (2 Sam 19:16-23), swearing <em>ʾim-tāmûṯ</em> (you shall not die) — but the oath was sworn by David, not by Solomon. David is technically not binding Solomon to inaction; he is transferring the obligation to Solomon's judgment (<em>wĕʾattâ tēḏaʿ ʾēṯ ʾăšer taʿăśeh-lô</em>, you know what you ought to do to him). David's oath protected Shimei during David's lifetime; Solomon's wisdom and justice now govern the matter.</p>",
        "9": "<p><strong>wĕhāyā-dāmô ʿal-rōʾšô</strong>: 'His blood will be on his own head.' The blood-guilt formula <em>dāmô ʿal-rōʾšô</em> (his blood on his head) is the standard legal idiom for self-incurred capital guilt in which the person's own actions are the cause of their death (Josh 2:19: Rahab's assurance that anyone who leaves her house = their blood on their own head; 1 Sam 25:39: Nabal's blood on his own head). David is not commanding Solomon to kill Shimei arbitrarily but pronouncing that Shimei's past crimes (cursing the LORD's anointed = capital offense under Exod 22:28) leave him with ongoing blood-guilt that will justify Solomon's action if and when he acts.</p>",
        "10": "<p><strong>wayyiškaḇ Dāwîḏ ʿim-ʾăḇōṯāyw wayyiqqāḇēr bĕʿîr Dāwîḏ</strong>: 'David slept with his fathers and was buried in the City of David.' <em>Wayyiškaḇ ʿim-ʾăḇōṯāyw</em> (he lay/slept with his fathers) is the standard death-formula for Israelite kings in 1-2 Kings — it will appear dozens of times. The burial in the <em>ʿîr Dāwîḏ</em> (City of David) is the royal burial location: the Davidic kings were buried in Jerusalem, in the royal necropolis on the original Jebusite hill. Acts 2:29 notes that David's tomb was known in Peter's day, confirming the long tradition of Davidic burial in Jerusalem.</p>",
        "11": "<p><strong>wĕhāyāmîm ʾăšer mālaḵ Dāwîḏ ʿal-yiśrāʾēl ʾarbaʿîm šānâ</strong>: 'The days that David reigned over Israel were forty years: seven years in Hebron and thirty-three years in Jerusalem.' The 40-year reign formula — <em>šeḇaʿ šānîm mālaḵ bĕḥeḇrôn ûšĕlōšîm wĕšālōš šānâ mālaḵ bîrûšālaim</em> — is an exact summary of 2 Sam 2:11 (7 years in Hebron) + 2 Sam 5:4-5 (33 in Jerusalem = 40 total). The 40-year period is the standard generation-length in OT chronology (wilderness: 40 years; Saul: 40 years; David: 40 years; Solomon: 40 years), though the specific figure for David has corroboration in the detailed chronological data of 2 Samuel.</p>",
        "12": "<p><strong>ûšĕlōmōh yāšaḇ ʿal-kissēʾ Dāwîḏ ʾāḇîw waṯiqqōn malKûṯô mĕʾōḏ</strong>: 'And Solomon sat on the throne of David his father, and his kingdom was firmly established greatly.' The verb <em>kûn</em> (Niphal, to be established/firm) is the root of the noun <em>nākôn</em> (established, secure). The Davidic covenant (2 Sam 7:12-16) used the same root: <em>wĕhăkinnōṯî ʾeṯ-malkûṯô</em> (I will establish his kingdom). Solomon's established kingdom is the initial fulfillment of the covenant promise — at least at the political level. The word <em>mĕʾōḏ</em> (greatly, exceedingly) emphasizes the completeness of the consolidation, which will be demonstrated in the elimination of the competing power centers (Adonijah, Joab, Abiathar, Shimei) in vv13-46.</p>",
        "13": "<p><strong>wayyāḇōʾ ʾAḏōniyyāhû ben-Ḥaggîṯ ʾel-Baṯ-šeḇaʿ ʾēm šĕlōmōh</strong>: 'Adonijah son of Haggith came to Bathsheba the mother of Solomon.' Adonijah's approach to Bathsheba rather than directly to Solomon is a political strategy: if he can get the queen mother to intercede, the request gains implicit backing from someone with standing before the king. The queen mother (<em>geḇîrâ</em>) in the Israelite and Judahite court had a recognized institutional role — 1 Kings 15:13 (Asa removes Maacah from the geḇîrâ position) and 2 Kings 10:13 (the sons of Ahaziah going to greet the sons of the queen mother) both suggest real political influence.</p>",
        "14": "<p><strong>wayyōʾmer lāh dāḇār šālôm lî waṯōʾmer šālôm</strong>: 'He said, I have something to say to you. She said, Speak.' The brief exchange is the formal request-to-speak protocol: the petitioner announces a desire to speak, the host invites. Bathsheba's simple <em>šālôm</em> (peace/well) is polite acceptance. She has no way to know at this point that the request is politically dangerous.</p>",
        "15": "<p><strong>wayyōʾmer ʾattâ yāḏaʿtā kî-lî hāyĕṯâ hammmamlāḵâ wĕʿālay śāmû kol-yiśrāʾēl p̄ānêhem limĕlōḵ</strong>: 'You know that the kingdom was mine, and that all Israel set their faces on me to reign.' Adonijah's claim that the kingdom was 'his' is the first indicator of his continuing illegitimate ambition. His self-justification — 'all Israel set their faces on me' — invokes popular support as the ground for his claim. But the Deuteronomistic History consistently evaluates succession claims by divine authorization (prophetic oracle, anointing) rather than popular acclamation. Adonijah's appeal to popular sentiment rather than divine appointment reveals the deficiency in his claim.</p>",
        "16": "<p><strong>wĕʿattâ šĕʾēlâ ʾaḥaṯ ʾānōḵî šōʾēl mēʾittāḵ ʾal-tĕḵabbî p̄ānāyiḵ</strong>: 'And now I am asking one request of you; do not refuse me.' The formal request structure — <em>šĕʾēlâ ʾaḥaṯ</em> (one petition) + <em>ʾal-tĕḵabbî p̄ānāyiḵ</em> (do not hide your face, i.e., do not refuse) — is the court petition formula. Bathsheba's <em>daḇḇērî</em> (speak!) accepts the petition for hearing. Adonijah has not yet revealed the content, but the elaborate setup signals the sensitivity of what he is about to request.</p>",
        "17": "<p><strong>wayyōʾmer ʾimrî nā lišĕlōmōh hammelek kî lōʾ-yāšîḇ ʾeṯ-p̄ānāyiḵ wĕyitten-lî ʾeṯ-ʾAḇîšaḡ haššûnammîṯ lĕʾiššâ</strong>: 'He said, Please speak to King Solomon — for he will not refuse you — that he give me Abishag the Shunammite as wife.' The request for Abishag is politically explosive: under ANE succession law, the harem of a deceased or deposed king passed to his successor (cf. 2 Sam 12:8; 16:21-22). Requesting one of the king's women — even if unconsummated — was equivalent to claiming succession rights. David 'did not know her' (1:4), but her status as the king's attendant was publicly known. Adonijah's request is therefore either deliberately provocative (a succession claim) or shows spectacular political naivety.</p>",
        "18": "<p><strong>waṯōʾmer Baṯ-šeḇaʿ ṭôḇ ʾānōḵî ʾăḏabbēr ʿāleykā ʾel-hammelek</strong>: 'Bathsheba said, Very well, I will speak for you to the king.' Bathsheba's agreement to intercede does not necessarily indicate she understands the political implications of the request; she may be acting in good faith as an intermediary. Alternatively, she may understand perfectly and is allowing Adonijah to expose himself. The narrator does not specify her motivation, leaving the reader to evaluate based on the outcome: the petition proves self-destructive for Adonijah.</p>",
        "19": "<p><strong>waṯāḇōʾ Baṯ-šeḇaʿ ʾel-hammelek šĕlōmōh lĕḏabbēr lô ʿal-ʾAḏōniyyāhû wayyāqom hammelek liqrāṯāh wayyišṯaḥû lāh</strong>: 'Bathsheba came to King Solomon to speak to him for Adonijah, and the king rose to meet her and bowed to her.' Solomon's reception of his mother — rising to meet her, bowing to her, providing a throne-seat at his right hand (<em>kissēʾ lĕʾēm hammelek waṯēšeḇ lîmînô</em>) — is the recognition of the queen-mother's institutional status. The <em>geḇîrâ</em> sitting at the king's right hand is the position of honor and authority in the court. This visual detail establishes the theological subtext: Bathsheba's request, given from this position of honor, should be persuasive.</p>",
        "20": "<p><strong>waṯōʾmer šĕʾēlâ qĕṭannâ ʾaḥaṯ ʾānōḵî šōʾeleṯ mēʾittāḵ ʾal-tāšēḇ ʾeṯ-p̄ānāy</strong>: 'She said, I ask one small request of you; do not refuse me.' The self-deprecation <em>qĕṭannâ</em> (small, little) before the petition is court rhetoric — Bathsheba minimizes the request to make refusal seem unreasonable. Solomon's response — <em>šăʾălî ʾimmi wĕlōʾ ʾāšîḇ ʾeṯ-p̄ānāyiḵ</em> (Ask, my mother, for I will not refuse you) — is the royal grant of a boon before knowing its content, a standard literary motif (cf. Mark 6:23: Herod's rash promise to Herodias's daughter). The unconditional promise sets up the narrative tension: Solomon has committed before hearing.</p>",
        "21": "<p><strong>waṯōʾmer yuttān ʾeṯ-ʾAḇîšaḡ haššûnammîṯ lĕʾAḏōniyyāhû ʾāḥîḵā lĕʾiššâ</strong>: 'She said, Let Abishag the Shunammite be given to Adonijah your brother as wife.' The request is delivered straightforwardly. Bathsheba's presentation of Adonijah as 'your brother' (<em>ʾāḥîḵā</em>) may be an attempt to soften the request by invoking fraternal obligation. Solomon's reaction — explosive anger — demonstrates that he immediately sees the political danger that Bathsheba perhaps did not.</p>",
        "22": "<p><strong>wayyaʿan hammmelek šĕlōmōh wayyōʾmer lĕʾimmô wĕlāmmâ ʾattî šōʾeleṯ ʾeṯ-ʾAḇîšaḡ haššûnammîṯ lĕʾAḏōniyyāhû ûšĕʾălî lô ʾeṯ-hammamlāḵâ</strong>: 'Solomon answered his mother, Why do you ask Abishag the Shunammite for Adonijah? Ask for him the kingdom as well!' Solomon's insight is rhetorical and sharp: <em>ûšĕʾălî lô ʾeṯ-hammamlāḵâ</em> (ask the kingdom for him too!) makes explicit what was implicit in the request. Because Adonijah is the next oldest son of David after the death of Amnon and Absalom, and because possession of the royal concubines/attendants was a succession symbol (2 Sam 16:21-22), the request for Abishag is tantamount to a succession claim. Solomon has identified the political threat clearly.</p>",
        "23": "<p><strong>wayyiššāḇaʿ hammmelek šĕlōmōh bĕYHWH lēʾmōr kōh yaʿăśeh-lî ʾĕlōhîm wĕḵōh yōsîp̄ kî bĕnap̄šô dibbēr ʾAḏōniyyāhû ʾeṯ-haddāḇār hazzeh</strong>: 'King Solomon swore by YHWH saying, God do so to me and more also if Adonijah has not spoken this word against his own life!' The oath formula <em>kōh yaʿăśeh-lî ʾĕlōhîm wĕḵōh yōsîp̄</em> (God do so to me and more) is the standard Hebrew self-imprecation — calling down divine judgment on oneself if the statement is false. The phrase <em>bĕnap̄šô dibbēr... ʾeṯ-haddāḇār hazzeh</em> (against his own life he spoke this word) means: the request itself is Adonijah's execution warrant; he has condemned himself by the petition.</p>",
        "24": "<p><strong>wĕʿattâ ḥay YHWH ʾăšer hĕḵînanî wayyōšîḇēnî ʿal-kissēʾ Dāwîḏ ʾāḇî wĕʾăšer ʿāśâ-lî ḇayiṯ kaʾăšer dibbēr kî hayyôm yûmāṯ ʾAḏōniyyāhû</strong>: 'As YHWH lives, who has established me and placed me on the throne of David my father and who has made me a house as he promised, today Adonijah shall be put to death.' The oath formula <em>ḥay YHWH</em> invokes the living God as guarantor. The relative clause establishes Solomon's theological ground: YHWH has established his throne and fulfilled his promise — this is covenant confirmation. Adonijah's attempt to undermine this YHWH-established order is therefore not merely political rebellion but theological provocation.</p>",
        "25": "<p><strong>wayišlaḥ hammelek šĕlōmōh bĕyaḏ Bĕnāyāhû ben-Yĕhôyāḏāʿ wayyippĕgaʿ-bô wayyāmōṯ</strong>: 'King Solomon sent by the hand of Benaiah son of Jehoiada, and he struck him and he died.' Benaiah's role as executioner throughout ch 2 (Adonijah: v25; Joab: v34; Shimei: v46) establishes him as the instrument of the royal justice administration. The verb <em>pāgaʿ</em> (to strike, meet with fatal result) is used for the execution of Agag by Samuel (1 Sam 15:32) and will be used again for Joab (v29). The brief, formulaic report — no detail of the execution, no lament — is the cold administrative register of the court chronicle.</p>",
        "26": "<p><strong>ûlĕʾAḇyāṯār hakkōhēn ʾāmar hammelek ʿAnāṯôṯ lēḵ ʿal-śāḏeykā kî ʾîš māweṯ ʾattâ</strong>: 'To Abiathar the priest the king said, Go to Anathoth to your field, for you are a man of death.' Solomon's judgment on Abiathar is banishment rather than execution — three reasons are given for mercy: (1) he carried the Ark (<em>nāśāʾtā ʾeṯ-ʾărôn ʾăḏōnāy YHWH</em>), (2) he was afflicted in all that David was afflicted (<em>ʾăšer hiṯʿannîṯā bĕḵōl ʾăšer-hiṯʿannâ ʾāḇî</em>), (3) the fulfillment of prophecy requires him to live to see it (v27). The phrase <em>ʾîš māweṯ ʾattâ</em> (you are a man of death, i.e., you deserve death) acknowledges the treason while explaining why the expected sentence is commuted.</p>",
        "27": "<p><strong>waygāreš šĕlōmōh ʾeṯ-ʾAḇyāṯār mĭhyôṯ kōhēn lĕYHWH lĕmallēʾ ʾeṯ-dĕḇar YHWH ʾăšer dibbēr ʿal-bêṯ ʿēlî bĕšîlōh</strong>: 'Solomon expelled Abiathar from being priest to YHWH, to fulfill the word of YHWH that he spoke concerning the house of Eli in Shiloh.' The explicit fulfillment formula — <em>lĕmallēʾ ʾeṯ-dĕḇar YHWH</em> (to fulfill the word of YHWH) — is one of the key theological moves in 1-2 Kings: events are interpreted as fulfillments of specific prophetic words. The 1 Sam 2:31-33 prophecy against Eli's house (no old man in Eli's line; a faithful priest will come) is here declared fulfilled. Abiathar is the last of Eli's priestly line in royal service; his expulsion ends that dynasty.</p>",
        "28": "<p><strong>wĕhaššĕmûʿâ bāʾâ ʿaḏ-Yôʾāḇ kî Yôʾāḇ nāṭâ ʾaḥărê ʾAḏōniyyāhû wĕʾaḥărê ʾAḇšālôm lōʾ nāṭâ</strong>: 'The news reached Joab — for Joab had turned after Adonijah, though after Absalom he had not turned.' The narrator's parenthetical — Joab followed Adonijah but not Absalom — is a calibrated observation: Joab's involvement in Absalom's rebellion was complex (he killed Absalom against David's orders) but he was never formally Absalom's partisan. His alignment with Adonijah was deliberate political choice. <em>Nāṭâ ʾaḥărê</em> (to turn/incline after) is the idiom for political allegiance.</p>",
        "29": "<p><strong>wayyuggad lišĕlōmōh kî-nās Yôʾāḇ ʾel-ʾōhel YHWH wĕhinnēh ʾēṣel hammizbēaḥ</strong>: 'Solomon was told that Joab had fled to the tent of YHWH and was by the altar.' Joab's flight to the altar sanctuary parallels Adonijah's in 1:50. But Joab refuses to leave when commanded — <em>lōʾ ʾāṣēʾ</em> (I will not go out) — unlike Adonijah who came down from the altar when summoned (1:53). Joab's altar-clinging is more desperate and more politically astute: he knows that leaving the sanctuary = execution. Solomon's command to Benaiah — 'go, fall upon him' (<em>lēḵ p̄ĕgaʿ-bô</em>) even at the altar — reflects the Exodus 21:14 exception: premeditated murder forfeits altar asylum rights.</p>",
        "30": "<p><strong>wayyāḇōʾ Bĕnāyāhû ʾel-ʾōhel YHWH wayyōʾmer ʾēlāyw kōh-ʾāmar hammelek ṣēʾ wayyōʾmer lōʾ kî p̄ōh ʾāmûṯ</strong>: 'Benaiah came to the tent of YHWH and said to him, Thus says the king, Come out. He said, No, for here I will die.' Joab's declaration — <em>p̄ōh ʾāmûṯ</em> (here I will die) — is a refusal of the sanctuary's conditional protection and a claim that only the altar-space will protect him. It is also the last act of defiance of a man who has resisted royal authority throughout the David narrative. The confrontation between Benaiah and Joab plays out the entire tension between institutional military power (the gibbôrîm under Benaiah, loyal to David/Solomon) and the older military establishment (Joab, loyal only to his own judgment).</p>",
        "31": "<p><strong>wayyōʾmer ʾēlāyw hammelek ʿăśēh kaʾăšer dibbēr wĕp̄ĕgaʿ-bô ûqĕḇartô</strong>: 'The king said to him, Do as he says; strike him and bury him.' Solomon's authorization for execution at the altar is based on Exod 21:14: 'if a man willfully attacks another to kill him treacherously, you shall take him from my altar, that he may die.' Joab's murders of Abner and Amasa were precisely treacherous, premeditated killings — the category for which altar asylum is explicitly denied. The burial command (<em>qĕḇartô</em>) is a sign of minimal respect: Joab's body will not be left unburied, though his execution is just. Verse 34 records the burial 'in his own house in the wilderness.'</p>",
        "32": "<p><strong>wĕhēšîḇ YHWH ʾeṯ-dāmô ʿal-rōʾšô</strong>: 'YHWH will return his blood on his head.' The theological interpretation of Joab's execution is explicitly given: this is YHWH's justice for the blood Joab shed. The formula <em>dāmô ʿal-rōʾšô</em> (blood on his head) — repeated in vv33, 37, 44 — is the covenant-justice formula of blood-guilt falling on the guilty party. Solomon is not merely executing a political rival; he is administering the covenant law of blood-guilt. The deaths of Abner and Amasa (and implicitly Uriah through Joab's complicity) are being legally addressed by the new king's justice.</p>",
        "33": "<p><strong>wĕhāyâ dĕmêhem bĕrōʾš Yôʾāḇ ûbĕrōʾš zarʿô lĕʿōlām</strong>: 'Their blood shall return upon the head of Joab and upon the head of his descendants forever.' The extension of blood-guilt to Joab's descendants (<em>zarʿô lĕʿōlām</em>) echoes the covenant curse-structure of Deut 28 — sins have generational consequences. The contrasting blessing — <em>wĕlĕḏāwîḏ ûlĕzarʿô ûlĕḇêṯô ûlĕkissĕʾô yihyeh šālôm ʿaḏ-ʿôlām mēʿim YHWH</em> (to David and his seed and his house and his throne there will be peace forever from YHWH) — is the covenant counterpart: the Davidic dynasty inherits perpetual peace while Joab's line inherits perpetual blood-guilt. The covenant binary is applied to specific individuals.</p>",
        "34": "<p><strong>wayyaʿal Bĕnāyāhû ben-Yĕhôyāḏāʿ wayyippĕgaʿ-bô wayyĕmîṯēhû wayyiqqāḇēr bĕḇêṯô bammiḏbār</strong>: 'Benaiah son of Jehoiada went up and attacked him and killed him, and he was buried in his own house in the wilderness.' The execution at the altar — <em>wayyaʿal</em> (went up, i.e., into the sanctuary) — is the enforcement of Exod 21:14. The burial notation (<em>bĕḇêṯô bammiḏbār</em>, in his house in the wilderness) suggests Joab's personal property was in the Judean wilderness, fitting for a warrior of his background. The execution of Joab completes the narrative arc begun in 2 Sam 3 (Abner's murder) — a three-book span before blood-guilt is finally addressed.</p>",
        "35": "<p><strong>wayyiṯṭēn hammelek ʾeṯ-Bĕnāyāhû ben-Yĕhôyāḏāʿ taḥtāyw ʿal-haṣṣāḇāʾ wĕʾeṯ-Ṣāḏôq hakkōhēn nāṯan hammelek taḥaṯ ʾAḇyāṯār</strong>: 'The king appointed Benaiah son of Jehoiada in his (Joab's) place over the army, and Zadok the priest the king appointed in place of Abiathar.' The succession of appointments — Benaiah for Joab, Zadok for Abiathar — completes the institutional restructuring. Both positions now belong to men who were loyal to Solomon from the beginning (Benaiah in 1:10; Zadok in 1:8). The Zadokite priestly line that will serve the Jerusalem temple through the exile is now established as the sole priestly dynasty, with Abiathar (Eli's last descendant) removed. Ezekiel's vision specifies the Zadokite priests as the legitimate priests of the eschatological temple (Ezek 44:15-16).</p>",
        "36": "<p><strong>wayišlaḥ hammelek wayyiqrāʾ-lišimʿî wayyōʾmer lô bĕnēh lĕḵā ḇayiṯ bîrûšālaim wĕyāšaḇtā šām</strong>: 'The king sent and called Shimei and said to him, Build yourself a house in Jerusalem and dwell there.' Solomon's terms for Shimei are precise: house arrest in Jerusalem, with the explicit boundary condition — <em>bĕyôm ṣēʾṯĕkā wĕʿāḇartā ʾeṯ-naḥal qiḏrôn yāḏōaʿ tēḏaʿ kî môṯ tāmûṯ</em> (on the day you go out and cross the Wadi Kidron, know for certain that you shall die). The Kidron Valley is the boundary of Jerusalem to the east; crossing it toward Bethlehem or the Jordan valley = unauthorized departure. The arrangement is a supervised mercy: Shimei lives, but under covenant terms whose violation will trigger death.</p>",
        "37": "<p><strong>wĕhāyâ bĕyôm ṣēʾṯĕkā wĕʿāḇartā ʾeṯ-naḥal qiḏrôn yāḏōaʿ tēḏaʿ kî môṯ tāmûṯ dāmeḵā yihyeh bĕrōʾšeḵā</strong>: 'On the day you go out and cross the Wadi Kidron, know certainly that you shall die; your blood will be on your own head.' The double infinitive <em>môṯ tāmûṯ</em> (dying you shall die = you shall surely die) is the emphatic death-sentence formula of Gen 2:17 and throughout the legal and narrative tradition. The blood-guilt formula (<em>dāmeḵā yihyeh bĕrōʾšeḵā</em>) makes the death self-incurred: Solomon is not threatening arbitrary execution but setting a boundary whose crossing = Shimei's own choice to forfeit the covenant of mercy. Shimei accepts the terms in v38.</p>",
        "38": "<p><strong>wayyōʾmer Šimʿî lammmelek ṭôḇ haddāḇār kĕʾăšer dibbēr ʾăḏōnî hammelek kēn yaʿăśeh ʿaḇdĕkā</strong>: 'Shimei said to the king, Good is the word; as my lord the king has said, so your servant will do.' Shimei's acceptance of the covenant terms is formal and explicit. <em>Ṭôḇ haddāḇār</em> (the word is good) is covenant ratification language — the party assents to the terms offered. The self-designation <em>ʿaḇdĕkā</em> (your servant) is the formula of submission. The narrator notes he dwelt in Jerusalem <em>yamîm rabbîm</em> (many days) — time passes, the boundary condition seems distant, and then Shimei violates it.</p>",
        "39": "<p><strong>wayĕhî miqṣēh šālōš šānîm wayyibrĕḥû šnê ʾăḇāḏîm lĕšimʿî ʾel-ʾĀḵîš ben-Maʿăḵâ melek Gaṯ</strong>: 'At the end of three years, two slaves of Shimei ran away to Achish son of Maacah king of Gath.' The three-year gap establishes that the covenant terms had been stable and observed before the crisis. The slaves' flight to Gath — Philistine territory, beyond the Kidron boundary — creates Shimei's dilemma: retrieve the slaves = violate the Kidron boundary = death; leave the slaves = loss of property. Shimei chooses to retrieve his slaves (<em>wayyaqom Šimʿî wayyaḥăbōš ʾeṯ-ḥămōrô wayyēleḵ Gaṯâ</em>), demonstrating that his material interests override the covenant terms he accepted.</p>",
        "40": "<p><strong>wayyāqom Šimʿî wayyaḥăbōš ʾeṯ-ḥămōrô wayyēleḵ Gaṯâ ʾel-ʾĀḵîš lĕḇaqēš ʾeṯ-ʿăḇāḏāyw</strong>: 'Shimei rose and saddled his donkey and went to Gath to Achish to seek his slaves.' The saddling of the donkey is the preparation-for-journey formula; the destination (Gath, Philistine territory) is unambiguous. The detail that Shimei went to retrieve slaves (<em>ʿăḇāḏāyw</em>) is the narrative's explanation of why he crossed the boundary — not a political escape attempt but a property recovery operation. Nevertheless, the violation is the violation: the specific boundary and condition were set by covenant, and Shimei crossed it.</p>",
        "41": "<p><strong>wayyuggad lišĕlōmōh kî hālaḵ Šimʿî mîrûšālaim Gaṯâ wayyāšāḇ</strong>: 'Solomon was told that Shimei had gone from Jerusalem to Gath and returned.' The report reaching Solomon — including both the departure and the return — triggers the execution. The covenant terms were explicit and Shimei had formally accepted them. Solomon's response follows the same legal logic as his response to Adonijah: the violation of the covenant term is self-incurred death (<em>dāmeḵā bĕrōʾšeḵā</em>). The legal precision of the Solomon narrative is characteristic: each execution is preceded by a specific covenant violation or crime.</p>",
        "42": "<p><strong>wayišlaḥ hammelek wayyiqrāʾ lĕšimʿî wayyōʾmer ʾēlāyw hălōʾ hišbaʿtîḵā ḇaYHWH</strong>: 'The king sent and called Shimei and said to him, Did I not make you swear by YHWH?' Solomon's confrontation with Shimei rehearses the covenant terms: the oath sworn by YHWH (<em>hišbaʿtîḵā ḇaYHWH</em>), the explicit warning (<em>ḥāʿēḏ bĕkā lēʾmōr</em>, I warned you), and the accepted terms (<em>môṯ tāmûṯ</em>). The phrase <em>waṯōʾmer ʾēlay ṭôḇ haddāḇār šāmaʿtî</em> (you said to me, Good is the word; I have heard) quotes back Shimei's own acceptance of the covenant in v38. The evidence against him is his own words.</p>",
        "43": "<p><strong>wĕlāmmâ lōʾ šāmartā ʾēṯ šĕḇûʿaṯ YHWH wĕʾeṯ-hammiṣwâ ʾăšer ṣiwwîṯî ʿāleykā</strong>: 'Why then have you not kept the oath of YHWH and the commandment I laid on you?' The language — <em>šĕḇûʿaṯ YHWH</em> (the oath of YHWH) and <em>miṣwâ</em> (commandment) — elevates the covenant terms from a political arrangement to a religious obligation. The oath sworn by YHWH as guarantor makes its violation an offense against YHWH, not merely against Solomon. This legal framing is consistent with the theological logic of 1-2 Kings: political covenants sworn by YHWH are covenant-theological obligations, not merely civil contracts.</p>",
        "44": "<p><strong>wayyōʾmer hammelek ʾel-Šimʿî ʾattâ yāḏaʿtā ʾēṯ kol-hārāʿâ ʾăšer yāḏaʿ lĕḇāḇĕkā ʾăšer ʿāśîṯā lĕḏāwîḏ ʾāḇî</strong>: 'The king said to Shimei, You know all the evil that your heart knows that you did to David my father.' Solomon's final statement before the execution invokes Shimei's prior crimes: the cursing of David during Absalom's rebellion (2 Sam 16:5-8), which Shimei knows in his own heart. <em>Yāḏaʿ lĕḇāḇĕkā</em> (your heart knows) — inner knowledge of guilt without external evidence required. The formula <em>wĕhēšîḇ YHWH ʾeṯ-rāʿāṯĕkā bĕrōʾšeḵā</em> (YHWH has returned your evil on your own head) is the divine-justice formula: YHWH administers the blood-guilt through the covenant community's judicial process.</p>",
        "45": "<p><strong>wĕhammelek šĕlōmōh bārûḵ ûkissēʾ Dāwîḏ yihyeh nāḵôn lip̄nê YHWH ʿaḏ-ʿôlām</strong>: 'King Solomon shall be blessed, and the throne of David shall be established before YHWH forever.' The chapter's theological climax inverts the blood-guilt formula: Shimei's evil falls on Shimei's head; Solomon's blessing is confirmed; David's throne is established before YHWH forever. <em>Lip̄nê YHWH ʿaḏ-ʿôlām</em> (before YHWH forever) is the Davidic covenant language of 2 Sam 7:16 — the throne established forever. The chapter ends not with political consolidation as its primary statement but with the fulfillment of the covenant promise.</p>",
        "46": "<p><strong>wayyĕṣaw hammelek ʾeṯ-Bĕnāyāhû ben-Yĕhôyāḏāʿ wayyēṣēʾ wayyippĕgaʿ-bô wayyāmōṯ ûmamlaḵâ nāḵônâ bĕyaḏ šĕlōmōh</strong>: 'The king commanded Benaiah son of Jehoiada and he went out and struck him and he died. And the kingdom was established in Solomon's hand.' The closing formula — <em>mamlaḵâ nāḵônâ bĕyaḏ šĕlōmōh</em> (the kingdom was established in Solomon's hand) — echoes the coronation statement of 2:12 (<em>waṯiqqōn malKûṯô mĕʾōḏ</em>) to form a chiastic bracket around the entire consolidation narrative of vv13-46. The root <em>kûn</em> (to be established, firm) is the Davidic covenant's establishment-word (2 Sam 7:12, 16); its application to Solomon's consolidated reign confirms that the covenant promise is now institutionally operative. The kingdom is 'in Solomon's hand' — not merely in name but in political reality.</p>"
    }
}


def main():
    existing = load_comm('mkt-original', '1kings')
    merge_comm(existing, KINGS1_ORIGINAL_CH1_2)
    save_comm('mkt-original', '1kings', existing)

    ch1 = existing.get('1', {})
    ch2 = existing.get('2', {})
    print(f'ch 1: {len(ch1)} verse entries')
    print(f'ch 2: {len(ch2)} verse entries')

    interlinear_path = ROOT / 'data' / 'interlinear' / '1kings.json'
    if interlinear_path.exists():
        il = json.loads(interlinear_path.read_text())
        for ch_num in ['1', '2']:
            il_verses = set(il.get(ch_num, {}).keys())
            comm_verses = set(existing.get(ch_num, {}).keys())
            missing = il_verses - comm_verses
            if missing:
                print(f'  ch {ch_num} missing: {sorted(missing, key=int)}')
            else:
                print(f'  ch {ch_num}: complete ({len(comm_verses)}/{len(il_verses)} verses)')


if __name__ == '__main__':
    main()
